public class Plane

{

// ===== תכונות =====

private int planeId;

private int numPass;

private int numEng;

public Plane(int planeId, int numPass, int numEng)

{

this.planeId = planeId;

this.numPass = numPass;

this.numEng = numEng;

}

public void AddPass(int additionalPass)

{

numPass += additionalPass;

}

public bool SamePlane(Plane other)

{

return this.numPass == other.numPass && this.numEng == other.numEng;

}

public static void AddToSmaller(Plane p1, Plane p2, int passengers)

{

if (p1.GetPass() < p2.GetPass())

{

p1.AddPass(passengers);

}

else if (p2.GetPass() < p1.GetPass())

{

p2.AddPass(passengers);

}

// אם מספר הנוסעים זהה – לא מתבצע דבר

}

static void Main(string[] args)

{

// יצירת שני מטוסים

Plane p1 = new Plane(101, 150, 3);

Plane p2 = new Plane(102, 150, 3);

Plane p3 = new Plane(103, 50, 2);

// בדיקה האם המטוסים זהים

if (p1.SamePlane(p2))

{

// אם המטוסים זהים – הוספת 50 נוסעים ל-p1

p1.AddPass(50);

}

else

{

// אם אינם זהים – הוספת 50 נוסעים למטוס עם פחות נוסעים

AddToSmaller(p1, p2, 50);

}

//Test for different planes

if (p1.SamePlane(p3))

p1.AddPass(50);

else

AddToSmaller(p1 , p3, 50);

// הדפסת מצב סופי לבדיקה

Console.WriteLine("Plane 1: Passengers = " + p1.GetPass() + ", Engines = " + p1.GetEng());

Console.WriteLine("Plane 2: Passengers = " + p2.GetPass() + ", Engines = " + p2.GetEng());

Console.WriteLine("Plane 3: Passengers = " + p3.GetPass() + ", Engines = " + p3.GetEng());

}
